import { LayoutType } from '../type/layout.type';

export class LayoutBase extends ComponentBase<LayoutType> {
  constructor(protected override type: LayoutType) {
    super(type);
  }
}

import { inject } from '@angular/core';
import { Store } from '@ngrx/store';
import { StoreType } from './store.type';

export class StoreCore {
  protected readonly store: Store<StoreType> = inject(Store);
}

export class StringUtility {
  static isEmpty(value?: string) {
    return value === undefined || value === null || value === '';
  }

  static isNotEmpty(value?: string) {
    return !this.isEmpty(value);
  }

  static convertToString(value: any) {
    return this.isEmpty(value) ? '' : value.toString();
  }
}

